class RsGetOrdersServiceImpl:
    def get_rs_orders(self, request):
        if request is None:
            raise ValueError("Request cannot be None")

        invoice_num = request.get('invoiceNum')
        if invoice_num is not None and not isinstance(invoice_num, str):
            raise TypeError("invoiceNum must be a string")

        request_type = request.get('requestType')
        if request_type not in ['type1', 'type2']:
            raise ValueError("Invalid requestType")

        # Simulate fetching orders based on the request
        orders = self.fetch_orders(invoice_num, request_type)
        return orders

    def fetch_orders(self, invoice_num, request_type):
        # Simulated database call
        return [{"orderId": 1, "invoiceNum": invoice_num, "requestType": request_type}]

# Unit tests
import unittest

class RsGetOrdersServiceImplTest(unittest.TestCase):
    def setUp(self):
        self.service = RsGetOrdersServiceImpl()

    def test_getRsOrders_invoiceNumNotNull_1(self):
        request = {'invoiceNum': '12345', 'requestType': 'type1'}
        result = self.service.get_rs_orders(request)
        self.assertIsNotNone(result)
        self.assertEqual(result[0]['invoiceNum'], '12345')

    def test_getRsOrders_invoiceNumNotNull_2(self):
        request = {'invoiceNum': '67890', 'requestType': 'type2'}
        result = self.service.get_rs_orders(request)
        self.assertIsNotNone(result)
        self.assertEqual(result[0]['invoiceNum'], '67890')

    def test_getRsOrders_requestTypeS(self):
        request = {'invoiceNum': '11111', 'requestType': 'type1'}
        result = self.service.get_rs_orders(request)
        self.assertEqual(result[0]['requestType'], 'type1')

if __name__ == '__main__':
    unittest.main()
